// Parse Claude's response and merge with metadata
const data = $input.first().json;
const webhookData = $node['Webhook: Image Ad Swipe'].json.body;

try {
  // Extract JSON from Claude response
  let responseText = data.content[0].text;
  // Strip markdown code blocks if present
  responseText = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const analysis = JSON.parse(responseText);

  // Get the public URL of the uploaded image
  const imageUrl = `https://wqclspynbdghfsosqygg.supabase.co/storage/v1/object/public/assets/ad-images/${webhookData.filename}`;

  return [{
    json: {
      image_url: imageUrl,
      headline_text: analysis.headline_text || null,
      body_copy: analysis.body_copy || null,
      cta_text: analysis.cta_text || null,
      hook_type: analysis.hook_type || null,
      copy_angle: analysis.copy_angle || null,
      emotional_appeal: analysis.emotional_appeal || null,
      layout_description: analysis.layout_description || null,
      color_palette: analysis.color_palette || {},
      font_style: analysis.font_style || null,
      visual_elements: analysis.visual_elements || null,
      recreation_prompt: analysis.recreation_prompt || null,
      triggers: analysis.triggers || [],
      niche: analysis.niche || webhookData.niche || 'general',
      performance_tag: 'untested'
    }
  }];
} catch (e) {
  // If parsing fails, return raw text as notes
  return [{
    json: {
      image_url: `https://wqclspynbdghfsosqygg.supabase.co/storage/v1/object/public/assets/ad-images/${webhookData.filename}`,
      niche: webhookData.niche || 'general',
      notes: data.content?.[0]?.text || 'Analysis failed',
      performance_tag: 'untested'
    }
  }];
}
